1	const PROCESSING_FEE = 5;
2	const BLOCK_SIZE = 3;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	const DEDUCTIBLE = 100;
5	
6	const INSURANCE_VALUES: Record<string, number> = {
7	  sword: 1000,
8	  amulet: 600,
9	  staff: 800,
10	  potion: 400,
11	  rune: 250,
12	  moonstone: 250,
13	};
14	
15	const BASE_PREMIUMS: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	  rune: 25,
21	  moonstone: 25,
22	};
23	
24	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
25	
26	const isComponent = (item: any): boolean => COMPONENT_TYPES.has(item.type);
27	
28	const basePremium = (item: any): number =>
29	  BASE_PREMIUMS[item.type] ?? 0;
30	
31	const countByType = (items: any[]): Record<string, number> => {
32	  const counts: Record<string, number> = {};
33	  for (const item of items) {
34	    counts[item.type] = (counts[item.type] ?? 0) + 1;
35	  }
36	  return counts;
37	};
38	
39	const componentGroupPremium = (type: string, count: number): number =>
40	  count === BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);
41	
42	const itemSurcharges = (item: any, base: number): number =>
43	  (item.cursed ? base * 0.5 : 0) + (item.enchantment >= 5 ? base * 0.3 : 0);
44	
45	const policyWideModifiers = (policyBase: number, customer: any, quoteIndex: number): number => {
46	  const firstInsurance = policyBase * 0.1;
47	  const loyaltyDiscount = customer.yearsWithMHPCO >= 2 ? -policyBase * 0.2 : 0;
48	  const followUpDiscount = quoteIndex > 0 ? -policyBase * 0.15 : 0;
49	  return firstInsurance + loyaltyDiscount + followUpDiscount;
50	};
51	
52	const quotePremium = (items: any[], customer: any, quoteIndex: number): number => {
53	  const components = items.filter(isComponent);
54	  const nonComponents = items.filter((item: any) => !isComponent(item));
55	  const componentTotal = Object.entries(countByType(components)).reduce(
56	    (sum: number, [type, count]: [string, number]) => sum + componentGroupPremium(type, count),
57	    0,
58	  );
59	  const { nonComponentBase, surchargesTotal } = nonComponents.reduce(
60	    (acc, item: any) => {
61	      const base = basePremium(item);
62	      return {
63	        nonComponentBase: acc.nonComponentBase + base,
64	        surchargesTotal: acc.surchargesTotal + itemSurcharges(item, base),
65	      };
66	    },
67	    { nonComponentBase: 0, surchargesTotal: 0 },
68	  );
69	  const policyBasePremium = nonComponentBase + componentTotal;
70	  return Math.ceil(policyBasePremium + surchargesTotal + policyWideModifiers(policyBasePremium, customer, quoteIndex) + PROCESSING_FEE);
71	};
72	
73	const insuranceSum = (items: any[]): number =>
74	  items.reduce((sum: number, item: any) => sum + (INSURANCE_VALUES[item.type] ?? 0), 0);
75	
76	const damageReimbursement = (damage: any, policyItem: any): number => {
77	  const amount = policyItem && policyItem.enchantment >= 8 ? damage.amount * 0.5 : damage.amount;
78	  return Math.max(0, amount - DEDUCTIBLE);
79	};
80	
81	const processClaim = (step: any, policy: any, remainingCap: number): any => {
82	  const totalPayout = step.incident.damages.reduce(
83	    (sum: number, damage: any) => {
84	      const policyItem = policy.items.find((item: any) => item.type === damage.itemType);
85	      return sum + damageReimbursement(damage, policyItem);
86	    },
87	    0,
88	  );
89	  const clampedPayout = Math.min(totalPayout, remainingCap);
90	  return { payout: Math.floor(clampedPayout), remainingCap: remainingCap - clampedPayout };
91	};
92	
93	export const processScenario = (scenario: any): any => {
94	  const policies: Record<number, any> = {};
95	  const caps: Record<number, number> = {};
96	  let quoteIndex = 0;
97	  return {
98	    results: scenario.steps.map((step: any, index: number) => {
99	      if (step.op === "claim") {
100	        const policyIndex = step.policy;
101	        if (caps[policyIndex] === undefined) {
102	          caps[policyIndex] = insuranceSum(policies[policyIndex].items) * 2;
103	        }
104	        const result = processClaim(step, policies[policyIndex], caps[policyIndex]);
105	        caps[policyIndex] = result.remainingCap;
106	        return result;
107	      }
108	      policies[index] = step;
109	      const result = { premium: quotePremium(step.items, scenario.customer, quoteIndex) };
110	      quoteIndex++;
111	      return result;
112	    }),
113	  };
114	};
